// ArtifactPanel - Modern Design with Blue/Indigo gradients (Updated 2026-02-13)
import { useState, useEffect } from 'react'
import {
  X,
  Copy,
  Download,
  Edit3,
  Save,
  FileText,
  Code,
  FileCode,
  Table,
  BarChart3,
  Check,
  Maximize2,
  Minimize2,
  ChevronDown
} from 'lucide-react'
import { Document, Packer, Paragraph, TextRun } from 'docx'
import { saveAs } from 'file-saver'
import { useArtifactStore } from '@/stores/artifactStore'
import { cn, copyToClipboard, downloadFile, getArtifactExtension } from '@/utils'
import type { Artifact } from '@/types'

export function ArtifactPanel() {
  const { 
    activeArtifactId,
    artifacts,
    isPanelOpen, 
    isFullscreen,
    closePanel, 
    updateArtifact,
    toggleFullscreen
  } = useArtifactStore()

  const activeArtifact = artifacts.find(a => a.id === activeArtifactId)

  const [isEditing, setIsEditing] = useState(false)
  const [editContent, setEditContent] = useState('')
  const [copied, setCopied] = useState(false)
  const [activeTab, setActiveTab] = useState<'preview' | 'code'>('preview')
  const [showDownloadMenu, setShowDownloadMenu] = useState(false)

  useEffect(() => {
    if (activeArtifact) {
      setEditContent(activeArtifact.content)
    }
  }, [activeArtifact?.id])

  // Debug: Log render state
  useEffect(() => {
    console.log('🎨 [ArtifactPanel] Render state:', {
      isPanelOpen,
      hasActiveArtifact: !!activeArtifact,
      activeArtifactId,
      totalArtifacts: artifacts.length,
      willRender: isPanelOpen && !!activeArtifact
    })
  }, [isPanelOpen, activeArtifact, activeArtifactId, artifacts.length])

  if (!isPanelOpen || !activeArtifact) {
    console.log('❌ [ArtifactPanel] Not rendering. isPanelOpen:', isPanelOpen, 'activeArtifact:', !!activeArtifact)
    return null
  }

  console.log('✅ [ArtifactPanel] Rendering panel for artifact:', activeArtifact.title)

  const getIcon = () => {
    const icons = {
      document: FileText,
      code: Code,
      table: Table,
      chart: BarChart3,
      html: Code,
    }
    const Icon = icons[activeArtifact.type] || FileText
    return <Icon className="w-[18px] h-[18px]" />
  }

  const handleEdit = () => {
    setEditContent(activeArtifact.content)
    setIsEditing(true)
  }

  const handleSave = () => {
    updateArtifact(activeArtifact.id, editContent)
    setIsEditing(false)
  }

  const handleCopy = async () => {
    await copyToClipboard(activeArtifact.content)
    setCopied(true)
    setTimeout(() => setCopied(false), 2000)
  }

  const handleDownloadTxt = () => handleDownloadFormat('txt')

  // Fase 2: Download em qualquer formato usando novo conversor
  const handleDownloadFormat = async (format: 'docx' | 'pdf' | 'html' | 'txt' | 'md') => {
    try {
      console.log(`[ArtifactPanel] Downloading as ${format.toUpperCase()}`)

      const response = await fetch('/api/convert', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          content: activeArtifact.content,
          format: format,
          title: activeArtifact.title,
          filename: activeArtifact.title.replace(/[^a-z0-9]/gi, '_').toLowerCase(),
          author: 'ROM Agent'
        })
      })

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({ error: 'Erro desconhecido' }))
        throw new Error(errorData.error || `Erro ao gerar ${format.toUpperCase()}`)
      }

      const blob = await response.blob()
      const fileExtensions: Record<string, string> = {
        docx: '.docx',
        pdf: '.pdf',
        html: '.html',
        txt: '.txt',
        md: '.md'
      }

      const filename = `${activeArtifact.title}${fileExtensions[format]}`
      saveAs(blob, filename)
      setShowDownloadMenu(false)

      console.log(`[ArtifactPanel] ✅ Downloaded as ${format.toUpperCase()}: ${filename}`)
    } catch (err: any) {
      console.error(`[ArtifactPanel] ❌ Error downloading ${format}:`, err)
      alert(`Erro ao gerar ${format.toUpperCase()}: ${err.message}`)
    }
  }

  const handleDownloadDocx = () => handleDownloadFormat('docx')

  const handleDownloadPDF = () => handleDownloadFormat('pdf')
  const handleDownloadHTML = () => handleDownloadFormat('html')
  const handleDownloadMarkdown = () => handleDownloadFormat('md')

  // Mobile sempre fullscreen, desktop respeitando isFullscreen
  const panelWidth = isFullscreen ? 'w-[70%] max-md:w-full' : 'w-[50%] max-w-[700px] max-md:w-full'

  return (
    <div
      className={cn(
        panelWidth,
        'h-screen bg-gradient-to-b from-white to-slate-50/30 border-l border-slate-200/60 flex flex-col shadow-xl',
        'animate-slide-in-right',
        'max-md:fixed max-md:right-0 max-md:top-0 max-md:z-50'
      )}
    >
      {/* Header - Clean modern design */}
      <div className="px-5 py-4 border-b border-slate-200/60 bg-white/80 backdrop-blur-sm flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="p-2.5 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-xl text-white shadow-md">
            {getIcon()}
          </div>
          <div>
            <h2 className="text-sm font-semibold text-slate-800">
              {activeArtifact.title}
            </h2>
            <span className="text-xs text-slate-500 font-medium">
              {activeArtifact.type === 'document' ? 'Documento Jurídico' :
               activeArtifact.type === 'code' ? `Código ${activeArtifact.language || ''}` :
               activeArtifact.type === 'table' ? 'Tabela' :
               activeArtifact.type === 'html' ? 'HTML' : 'Gráfico'}
            </span>
          </div>
        </div>

        <div className="flex items-center gap-2">
          {/* Actions */}
          <div className="flex items-center gap-2 mr-2">
            {isEditing ? (
              <button
                onClick={handleSave}
                className="flex items-center gap-1.5 px-3 py-1.5 bg-gradient-to-r from-blue-500 to-indigo-600 text-white rounded-lg text-xs font-semibold hover:shadow-md transition-all hover:scale-[1.02] shadow-sm"
              >
                <Save className="w-3.5 h-3.5" />
                Salvar
              </button>
            ) : (
              <button
                onClick={handleEdit}
                className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-100 text-slate-700 rounded-lg text-xs font-medium hover:bg-slate-200 transition-all border border-slate-200/80"
              >
                <Edit3 className="w-3.5 h-3.5" />
                Editar
              </button>
            )}

            <button
              onClick={handleCopy}
              className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-100 text-slate-700 rounded-lg text-xs font-medium hover:bg-slate-200 transition-all border border-slate-200/80"
            >
              {copied ? (
                <>
                  <Check className="w-3.5 h-3.5" />
                  Copiado!
                </>
              ) : (
                <>
                  <Copy className="w-3.5 h-3.5" />
                  Copiar
                </>
              )}
            </button>

            {/* Download dropdown */}
            <div className="relative">
              <button
                onClick={() => setShowDownloadMenu(!showDownloadMenu)}
                className="flex items-center gap-1.5 px-3 py-1.5 bg-gradient-to-r from-blue-500 to-indigo-600 text-white rounded-lg text-xs font-semibold hover:shadow-md transition-all hover:scale-[1.02] shadow-sm"
              >
                <Download className="w-3.5 h-3.5" />
                Baixar
                <ChevronDown className="w-3 h-3" />
              </button>

              {showDownloadMenu && (
                <>
                  <div
                    className="fixed inset-0 z-10"
                    onClick={() => setShowDownloadMenu(false)}
                  />
                  <div className="absolute right-0 mt-1 w-56 bg-white rounded-lg border border-stone-200 shadow-lg z-20 py-1">
                    <button
                      onClick={handleDownloadDocx}
                      className="w-full px-4 py-2 text-left text-sm text-stone-700 hover:bg-stone-50 flex items-center gap-2"
                    >
                      <FileText className="w-4 h-4" />
                      Word (.docx)
                    </button>
                    <button
                      onClick={handleDownloadPDF}
                      className="w-full px-4 py-2 text-left text-sm text-stone-700 hover:bg-stone-50 flex items-center gap-2"
                    >
                      <FileText className="w-4 h-4" />
                      PDF (.pdf)
                    </button>
                    <button
                      onClick={handleDownloadHTML}
                      className="w-full px-4 py-2 text-left text-sm text-stone-700 hover:bg-stone-50 flex items-center gap-2"
                    >
                      <Code className="w-4 h-4" />
                      HTML (.html)
                    </button>
                    <button
                      onClick={handleDownloadMarkdown}
                      className="w-full px-4 py-2 text-left text-sm text-stone-700 hover:bg-stone-50 flex items-center gap-2"
                    >
                      <FileCode className="w-4 h-4" />
                      Markdown (.md)
                    </button>
                    <div className="border-t border-stone-200 my-1" />
                    <button
                      onClick={handleDownloadTxt}
                      className="w-full px-4 py-2 text-left text-sm text-stone-700 hover:bg-stone-50 flex items-center gap-2"
                    >
                      <FileText className="w-4 h-4" />
                      Texto (.txt)
                    </button>
                    <div className="border-t border-stone-200 my-1" />
                    <div className="px-4 py-2 text-xs text-stone-500">
                      Formatação: ABNT/OAB
                    </div>
                  </div>
                </>
              )}
            </div>
          </div>

          <button
            onClick={toggleFullscreen}
            className="p-2 hover:bg-slate-100 rounded-lg text-slate-600 hover:text-slate-900 transition-all"
            title={isFullscreen ? "Minimizar" : "Tela cheia"}
          >
            {isFullscreen ? <Minimize2 className="w-4 h-4" /> : <Maximize2 className="w-4 h-4" />}
          </button>

          <button
            onClick={closePanel}
            className="p-2 hover:bg-red-50 rounded-lg text-slate-600 hover:text-red-600 transition-all"
            title="Fechar"
          >
            <X className="w-4 h-4" />
          </button>
        </div>
      </div>

      {/* Tabs - Clean modern design */}
      <div className="px-5 py-3 bg-white border-b border-slate-200/60 flex gap-2">
        <button
          onClick={() => setActiveTab('preview')}
          className={cn(
            'px-4 py-2 rounded-lg text-xs font-semibold transition-all',
            activeTab === 'preview'
              ? 'bg-gradient-to-r from-blue-500 to-indigo-600 text-white shadow-sm'
              : 'bg-slate-50 text-slate-700 hover:bg-slate-100 border border-slate-200/60'
          )}
        >
          📄 Visualizar
        </button>
        <button
          onClick={() => setActiveTab('code')}
          className={cn(
            'px-4 py-2 rounded-lg text-xs font-semibold transition-all',
            activeTab === 'code'
              ? 'bg-gradient-to-r from-blue-500 to-indigo-600 text-white shadow-sm'
              : 'bg-slate-50 text-slate-700 hover:bg-slate-100 border border-slate-200/60'
          )}
        >
          💻 Código
        </button>
      </div>

      {/* Content - Clean, modern, spacious styling */}
      <div className="flex-1 overflow-auto p-6 bg-gradient-to-b from-slate-50/50 to-white">
        {isEditing ? (
          <textarea
            value={editContent}
            onChange={(e) => setEditContent(e.target.value)}
            className="w-full h-full p-5 bg-white border border-slate-200/60 rounded-2xl font-mono text-sm text-slate-800 resize-none focus:outline-none focus:border-blue-400 focus:ring-4 focus:ring-blue-100 shadow-sm transition-all"
            placeholder="Edite o conteúdo do documento..."
          />
        ) : activeTab === 'code' ? (
          <div className="bg-white border border-slate-200/60 rounded-2xl p-5 shadow-sm">
            <pre className="font-mono text-sm leading-relaxed">
              {activeArtifact.content.split('\n').map((line, i) => (
                <div key={i} className="flex hover:bg-blue-50/50 -mx-5 px-5 py-0.5 transition-colors rounded">
                  <span className="w-12 text-right pr-4 text-slate-400 select-none font-medium">
                    {i + 1}
                  </span>
                  <span className="text-slate-800 flex-1">{line || ' '}</span>
                </div>
              ))}
            </pre>
          </div>
        ) : (
          <div className="prose-chat bg-white border border-slate-200/60 rounded-2xl p-8 shadow-sm">
            <pre className="whitespace-pre-wrap font-sans text-[15px] leading-relaxed text-slate-800">
              {activeArtifact.content}
            </pre>
          </div>
        )}
      </div>
    </div>
  )
}
